// import React from 'react';
function ProductTable({products}) {
    return (
        <table border="1" cellPadding={10} cellSpacing={5}>
            <thead>
                <tr>
                    <th>ID</th>
                    <th>Product Name</th>
                    <th>Price</th>
                    <th>Category</th>
                    <th>Rating</th>
                    <th>Image</th>
                </tr>
            </thead>

            <tbody>

                {products.map((item) => {
                    return (
                        <tr key={item.id}>
                            <td>{item.id}</td>
                            <td>{item.title}</td>
                            <td>{item.price}</td>
                            <td>{item.category}</td>
                            <td>{item.rating.rate}</td>
                            <td>
                                <img src={item.image} height="200" width="200" style={{ textAlign: "center"}} />
                            </td>
                        </tr>
                    )

                })}
            </tbody>

        </table>
    )
}

export default ProductTable;